"""
MKT Original Language Commentary — Nehemiah chapters 7–8
Run: python3 scripts/zc-original-nehemiah-7-8.py

Ch 7: The genealogical register — parallel to Ezra 2 with variant numbers; theological
      function of genealogy; those unable to prove lineage; the Urim/Thummim provision.
Ch 8: The great Torah reading assembly — the foundational text for biblical exposition;
      məpōrāš, śêḵel, and the triad of read/explain/apply; "joy of the LORD is your strength";
      the Sukkoth discovery and its fulfillment from Joshua's day.

Key linguistic observations: the divine-heart-prompting idiom (7:5); the genealogical
theology of numbers in 7:8-60; Urim/Thummim as oracle (7:65); the exposition triad
(8:8); the hapax "joy of the LORD" (8:10); understanding (bîn) as the goal of Torah reading.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NEH = {
  "7": {
    "1": "<p><strong>wayyəhî kəʾăšer niwwənəṯāh haḥômāh</strong> — 'After the wall was built (<em>bānāh</em>, niphal perfect) and the doors set in place.' The niphal passive marks completion — the work is presented as a fait accompli before the administrative sequel begins. The sequence: building complete → appointments made → registration ordered. Nehemiah's first act after wall completion is not celebration but institutional organization, reflecting the scribal/administrative temperament that defines his memoir.</p>",
    "2": "<p><strong>waʾăṣawweh ʾeṯ-ʾāḥî Ḥănānî wəʾeṯ-Ḥănanyāh śar habbîrāh</strong> — 'I put my brother Hanani and Hananiah the commander of the citadel (<em>bîrāh</em>, H1002) in charge of Jerusalem.' <em>Bîrāh</em> (Aramaic loanword = fortress/citadel) designates the fortified palace compound on the temple mount. Hananiah is commended with two parallel qualifiers: <em>kî-hûʾ kəʾîš ʾĕmet</em> ('for he was a man of faithfulness/truth,' H571) and <em>wəyārēʾ ʾeṯ-hāʾĕlōhîm mēharabbîm</em> ('feared God more than the many'). <em>ʾĕmet</em> is the Torah-faithfulness term; the comparative <em>mēharabbîm</em> ('more than many') is a Hebrew elative — the highest degree of the quality within a comparison group.</p>",
    "3": "<p><strong>ʿad ḥōm haššemeš yippāṯəḥû</strong> — 'Let them not open [the gates] until the sun is hot.' The imperfect with negation (<em>ʾal + yippaʿal</em>) = jussive prohibition. <em>Ḥōm haššemeš</em> — 'when the sun is hot' = mid-morning, well after dawn when enemies might attempt a surprise raid. The security protocol reflects the reality that the recently-rebuilt wall was still vulnerable until the population density increased. <strong>wəhāʿămadtî mišmārōt</strong> — 'I appointed guards' — hiphil of <em>ʿāmaḏ</em> (H5975): to station/appoint.</p>",
    "4": "<p><strong>hāʿîr rəḥāḇat yādayim ûgəḏôlāh</strong> — 'the city was wide of hands and large.' <em>Rəḥāḇat yādayim</em> (lit. 'broad of hands') is a Hebrew spatial idiom for open space, room to spread out (cf. Judg 18:10 'a place where there is no lack of anything'). The population gap is expressed with the same word: <em>wəhāʿām məʿaṭ bəṯôkāh</em> — 'the people within it were few.' The contrast (large city, few inhabitants) sets up the necessity of the genealogical registration in v5.</p>",
    "5": "<p><strong>wayyittēn ʾĕlōhay ʾel-libbî</strong> — 'my God put it into my heart.' This divine-prompting idiom (<em>nātan ʾel-lēḇ</em>) recurs throughout Nehemiah (2:12; 7:5; cf. Ezra 7:27 for Artaxerxes). The heart (<em>lēḇ</em>) is the organ of intention and decision; YHWH's action is interior, not by external command or vision. <strong>lihitṯyaḥēś</strong> — infinitive of <em>yāḥas</em> (H3187, hithpael = to register oneself genealogically, to enroll in the family registry). Genealogical registration (<em>sepher hayyaḥas</em>) is the mechanism for establishing covenant membership.</p>",
    "6": "<p><strong>ʾēlleh bənê hammədînāh</strong> — 'these are the people of the province' (<em>mədînāh</em>, H4082 = administrative district). The same opening formula as Ezra 2:1 (ʾēlleh bənê hammədînāh haʿōlîm miššəḇî haggôlāh). Nehemiah 7:6-73 is a near-duplicate of Ezra 2 — the same list preserved in two books with minor variants in names and numbers. The textual variants (most numbers differ slightly between Ezra 2 and Neh 7) are significant for textual criticism: they indicate two independent copies of the same original register were preserved, with scribal transmission errors producing divergent numerals. The LXX sometimes harmonizes; MT preserves the variants.</p>",
    "7": "<p><strong>ʾăšer-bāʾû ʿim-Zərūbbāḇel</strong> — 'who came with Zerubbabel.' The 12 leaders listed (Zerubbabel, Jeshua, Nehemiah, Azariah, Raamiah, Nahamani, Mordecai, Bilshan, Mispereth, Bigvai, Nehum, Baanah) match Ezra 2:2 almost identically with minor name variants. The Nehemiah in this list (v7) is not Nehemiah son of Hachaliah (the author); the same register serves both Ezra and Nehemiah because it predates both compilations and records the original Zerubbabel-era return (ca. 536 BCE).</p>",
    "8": "<p>Parosh: 2,172 (cf. Ezra 2:3: 2,172 — match). The genealogical register lists family groups (<em>bənê</em> = 'sons/descendants of') by patriarch's name. <em>Parosh</em> ('flea') is an otherwise unattested personal name; its post-exilic survival as a family-group name demonstrates the Israelite practice of naming by ancestor even when the original individual is obscure. Most numbers in this list diverge from Ezra 2; Parosh is one of the rare matches.</p>",
    "9": "<p>Shephatiah: 372 (cf. Ezra 2:4: 372 — match). <em>Šəpaṭyāh</em> = 'YHWH has judged' — a theophoric name bearing witness to divine justice. The variants between Ezra 2 and Nehemiah 7 in individual family counts (most diverge by small amounts: e.g., Arah = 652 here vs. 775 in Ezra 2:5) most likely reflect different stages of counting: the Ezra list may count all who set out; the Nehemiah list those who arrived and settled. Alternatively, the divergences reflect scribal transmission errors in numerals, which are statistically more prone to corruption than text.</p>",
    "10": "<p>Arah: 652 (cf. Ezra 2:5: 775 — significant divergence of 123). <em>ʾAraḥ</em> = 'wayfarer/traveler.' The 652 vs. 775 divergence for Arah is the largest numerical discrepancy in the two lists. The Chronicler (1 Esdras, a Greek reworking) harmonizes to 652. The MT preserves both variants without harmonization, which is a sign of textual fidelity: a later editor would be more tempted to harmonize than to preserve divergent numbers from two authoritative sources.</p>",
    "11": "<p>Pahathmoab/Jeshua and Joab: 2,818 (cf. Ezra 2:6: 2,812 — diverge by 6). The family name <em>Paḥaṯ-môʾāḇ</em> ('governor of Moab') suggests an ancestor who governed Moabite territory. The compound family group (through Jeshua and Joab) indicates that the original Pahathmoab clan had split into two sub-branches (<em>lišnê</em> = 'through two'), both counted together in the total.</p>",
    "12": "<p>Elam: 1,254 (cf. Ezra 2:7: 1,254 — match). <em>ʿÊlām</em> is both an Elamite geographic name and a Hebrew personal name ('eternity/hidden'). The exact match here contrasts with nearby divergent numbers, suggesting the Elam total was transmitted stably. Elam also appears as a separate entry in v34 ('the other Elam,' 1,254), raising the question of whether two clans bore the same ancestor's name.</p>",
    "13": "<p>Zattu: 845 (cf. Ezra 2:8: 945 — diverge by 100). A round-number divergence of 100 is a common scribal error pattern: the numeral for 100 in ancient Hebrew was a single stroke that could be dropped in copying. The family name <em>Zattûʾ</em> is of uncertain etymology.</p>",
    "14": "<p>Zaccai: 760 (cf. Ezra 2:9: 760 — match). <em>Zakkay</em> = 'innocent, pure' — a theologically loaded personal name affirming God's verdict of innocence. The match confirms stable transmission for this entry.</p>",
    "15": "<p>Binnui: 648 (cf. Ezra 2:10: Bani 642 — diverge by 6 and name variant). Neh 7 has <em>Binnûy</em> while Ezra 2 has <em>Bānî</em> — a name variant that suggests either two distinct ancestors or orthographic confusion between <em>binnûy</em> (built) and <em>bānî</em> (builder). Such name variants alongside numerical divergences are characteristic of lists transmitted independently through different archival channels.</p>",
    "16": "<p>Bebai: 628 (cf. Ezra 2:11: 623 — diverge by 5). <em>Bēḇay</em> is of uncertain etymology, possibly Babylonian in origin — a personal name acquired during the exile. The small divergences (5, 6) in several entries likely represent genuine archival variant copies rather than systematic error.</p>",
    "17": "<p>Azgad: 2,322 (cf. Ezra 2:12: 1,222 — diverge by 1,100). The Azgad divergence is dramatic — 2,322 vs. 1,222 differs by 1,100 and cannot be explained by simple scribal error. The name <em>ʿAzgāḏ</em> ('Gad is strong') was a large clan with multiple sub-groups; possibly the Nehemiah figure incorporates descendants of returnees who joined in subsequent waves. This divergence is one of the strongest arguments that the two lists represent genuinely different recensions of the register.</p>",
    "18": "<p>Adonikam: 667 (cf. Ezra 2:13: 666 — diverge by 1). The one-digit difference for <em>ʾAḏônîqām</em> ('my lord has risen') likely represents a copying error — the Hebrew for 667 differs from 666 by a single letter in some scripts. Ezra 8:13 refers to 'the later sons of Adonikam' (60 males) coming with Ezra, suggesting the family continued to send members to Judah over time.</p>",
    "19": "<p>Bigvai: 2,067 (cf. Ezra 2:14: 2,056 — diverge by 11). <em>Bigway</em> is a Persian name (cf. Bagoas/Bagohi, a Persian official attested in Elephantine papyri). The use of a Persian name as an ancestral family designation indicates that some post-exilic families took Persian names during the Babylonian/Persian period. Their inclusion in the covenant community demonstrates that Persian naming did not compromise covenant membership.</p>",
    "20": "<p>Adin: 655 (cf. Ezra 2:15: 454 — diverge by 201). A large divergence suggesting different counting methods or time periods. <em>ʿĀḏîn</em> = 'delicate/soft' — a name; Ezra 8:6 lists another contingent of Adin's descendants returning with Ezra.</p>",
    "21": "<p>Ater/Hezekiah: 98 (cf. Ezra 2:16: 98 — match). <em>ʾĀṭēr</em> = 'lame, bound.' The parenthetical gloss '<em>lĕḥizqiyyāh</em>' (= 'that is, of Hezekiah') clarifies that this Ater is identified with a family known by the theophoric name Hezekiah ('YHWH is my strength') rather than by the patron's personal name Ater. The alternation between personal names and theophoric names within the same family group is common in post-exilic genealogies.</p>",
    "22": "<p>Hashum: 328 (cf. Ezra 2:19: 223 — diverge by 105). A large divergence. <em>Ḥāšûm</em> = possibly 'broad-nosed.' Ezra 10:33 lists sons of Hashum among those with foreign wives — the same family group appears in the community's failure as well as its return.</p>",
    "23": "<p>Bezai: 324 (cf. Ezra 2:17: 323 — diverge by 1). One-digit difference. <em>Bēṣay</em> is of uncertain meaning. The small one-digit divergence is the most common numerical variant type, consistent with individual scribal copying errors rather than different traditions.</p>",
    "24": "<p>Hariph: 112 (cf. Ezra 2: not listed separately as Hariph, but Jorah: 112 — match on number, name variant). <em>Ḥārîp̄</em> ('autumn rain') vs. <em>Yôrāh</em> ('early rain'): both rain-related names; the numerical match with the name variant may indicate the same family recorded under two different ancestor names.</p>",
    "25": "<p>Gibeon: 95 (cf. Ezra 2:20: Gibbar 95 — match on number, name variant). <em>Giḇʿôn</em> (the city) vs. <em>Gibbār</em> (a man's name). The geographic vs. personal name variant suggests one tradition recorded the city of origin while the other recorded the family patriarch's name. Geographic identifiers becoming family names is well attested in post-exilic communities.</p>",
    "26": "<p>Bethlehem and Netophah: 188 (cf. Ezra 2:21-22: Bethlehem 123, Netophah 56 = 179 total — diverge by 9). Nehemiah combines these two villages into a single entry; Ezra lists them separately. <em>Bêṯ lāḥem</em> ('house of bread/food') and <em>Nəṭôp̄āh</em> ('dripping') are towns near Jerusalem. Bethlehem is of Messianic significance (Mic 5:2), but that significance is not invoked here; the list is administrative, not theological.</p>",
    "27": "<p>Anathoth: 128 (cf. Ezra 2:23: 128 — match). <em>ʿĂnāṯôṯ</em> is the priestly town of Jeremiah's birth (Jer 1:1). The exact match and the city's prophetic associations make this entry notable. The returnees from Anathoth carry the legacy of the Levitical town from which came the prophet who most fully proclaimed the Babylonian exile as YHWH's judgment.</p>",
    "28": "<p>Beth-azmaveth: 42 (cf. Ezra 2:24: Azmaveth 42 — match with slightly different name form). <em>Bêṯ-ʿazmāweṯ</em> ('house of the strong one of death/Azmaveth') vs. <em>ʿAzmāweṯ</em> alone; the addition of <em>bêṯ</em> (house/place) is a typical site-name formation. Small community of 42.</p>",
    "29": "<p>Kiriath-jearim, Chephirah, and Beeroth: 743 (cf. Ezra 2:25: 743 — match). Three Gibeonite towns (Josh 9:17) — their returnees are grouped together, preserving the memory of the old Gibeonite confederacy within the post-exilic register. The Gibeonites (the subject of the treaty in Josh 9) appear indirectly in the exile community through towns that bore their settlement heritage.</p>",
    "30": "<p>Ramah and Geba: 621 (cf. Ezra 2:26: 621 — match). <em>Rāmāh</em> ('height') and <em>Geḇaʿ</em> ('hill') are paired towns north of Jerusalem. Ramah was Rachel's traditional burial site (Jer 31:15) and a Levitical city; Geba marked the northern boundary of Judah (2 Kgs 23:8). The exact numerical match confirms stable transmission.</p>",
    "31": "<p>Michmas: 122 (cf. Ezra 2:27: 122 — match). <em>Mikmās</em> — the town near which Jonathan defeated the Philistines (1 Sam 13-14). The town's return to Jewish settlement is an implicit restoration of the Benjamin-territory geography.</p>",
    "32": "<p>Bethel and Ai: 123 (cf. Ezra 2:28: 223 — diverge by 100). A hundred-unit divergence — the same scribal error pattern as Zattu (v13). <em>Bêṯ-ʾēl</em> ('house of God') and <em>ʿĀy</em> ('ruin') are adjacent towns with deep Abrahamic and conquest-era associations (Gen 12:8; Josh 7-8). Their repopulation is part of the broader restoration of the Benjaminite hill country.</p>",
    "33": "<p>The other Nebo: 52 (cf. Ezra 2:29: 52 — match). Called 'the other Nebo' (<em>nəḇô ʾaḥēr</em>) to distinguish from the first Nebo mentioned in the Transjordan. The adjective <em>ʾaḥēr</em> ('other') is a gloss distinguishing two places with the same name — editorial clarification within the archival record.</p>",
    "34": "<p>The other Elam: 1,254 (cf. Ezra 2:31: 1,254 — match). Two Elam entries in the list (v12 and v34), both with 1,254 — an unusual exact duplication. The <em>ʾaḥēr</em> ('other') gloss distinguishes them. Possibly two distinct clans bearing the same ancestor's name; or a scribal duplication in the original register. The exact numerical match across both entries is statistically remarkable if they are independent traditions.</p>",
    "35": "<p>Harim: 320 (cf. Ezra 2:32: 320 — match). <em>Ḥārîm</em> = 'snub-nosed' or 'devoted.' The priestly Harim family also appears in v42 among the priests (1,017 members) — different branches sharing an ancestor. The lay Harim of v35 and the priestly Harim of v42 are distinct genealogical lines that share the same family name.</p>",
    "36": "<p>Jericho: 345 (cf. Ezra 2:34: 345 — match). The return of Jericho's people (<em>yərîḥô</em>) is theologically resonant — the first city conquered in the land (Josh 6) is among the first repopulated in the return. <em>Yərîḥô</em> is of uncertain etymology; possibly related to <em>yārêaḥ</em> ('moon') suggesting a pre-Israelite lunar cult site.</p>",
    "37": "<p>Lod, Hadid, and Ono: 721 (cf. Ezra 2:33: 725 — diverge by 4). Three coastal towns in the Shephelah. <em>Lōḏ</em> is mentioned in the NT as Lydda (Acts 9:32-35, where Peter heals a paralyzed man). The four-digit divergence in this entry is small and consistent with independent transmission.</p>",
    "38": "<p>Senaah: 3,930 (cf. Ezra 2:35: 3,630 — diverge by 300). The largest entry in the register and a large divergence (300). <em>Sənaʾāh</em> is otherwise unknown as a town but may designate a district or occupational guild (possibly weavers or craftsmen who settled together). The 3,930/3,630 divergence involves the numeral for 300, consistent with the numeral-scribal-error pattern seen in other entries.</p>",
    "39": "<p>The priests begin at v39-42 with four priestly families: Jedaiah/house of Jeshua: 973 (cf. Ezra 2:36: 973 — match). The transition to priestly families (<em>hakkōhănîm</em>) marks the shift from lay to temple-service genealogies. The priestly totals are larger per family than most lay entries, reflecting the extensive priestly apparatus required for daily sacrificial service. The fact that specific numbers are preserved — not rounded — suggests use of actual temple registration records.</p>",
    "40": "<p>Immer: 1,052 (cf. Ezra 2:37: 1,052 — match). <em>ʾImmēr</em> is a priestly clan name (cf. Jer 20:1, Pashhur son of Immer imprisoned Jeremiah). The exact match across both Ezra and Nehemiah for the Immer total confirms stable transmission of the priestly registers — these records were more carefully maintained than lay genealogies.</p>",
    "41": "<p>Pashur: 1,247 (cf. Ezra 2:38: 1,247 — match). The priestly Pashur family (distinct from the Pashhur/Immer connection in Jer 20:1) is among the largest priestly clans. Exact match again.</p>",
    "42": "<p>Harim: 1,017 (cf. Ezra 2:39: 1,017 — match). The fourth priestly family, completing the four-family priestly block (vv39-42). All four priestly totals match exactly between Ezra 2 and Neh 7 — a strong indicator that priestly genealogical records were transmitted with greater care than lay registers, as would be expected given the importance of genealogical verification for priestly office.</p>",
    "43": "<p>The Levites: Jeshua/Kadmiel/Hodevah: 74 (cf. Ezra 2:40: Jeshua/Kadmiel/Hodaviah: 74 — match with minor name variant). The Levitical total is strikingly small (74) compared to the priestly total (4,289). The disproportionately small Levite contingent was noted in Ezra 8:15 — Levites were reluctant to return. The name variant <em>Hôḏəwyāh</em> (Ezra) / <em>Hôḏěwyāh</em> (Nehemiah) is an orthographic/vocalic variant of the same name.</p>",
    "44": "<p>The singers: descendants of Asaph: 148 (cf. Ezra 2:41: 128 — diverge by 20). <em>ʾĀsāp̄</em> ('gatherer') is the eponymous ancestor of the Levitical singing guild (1 Chr 6:39; Ps 73-83 are Asaphite psalms). The 20-person divergence may reflect additional singers from Asaph's family who joined between the initial return and the Nehemiah-era registration.</p>",
    "45": "<p>The gatekeepers: six named clans totaling 138 (cf. Ezra 2:42: 139 — diverge by 1). The gatekeepers (<em>šōʿărîm</em>, H7778) held a prestigious Levitical post — guarding the entrances to the temple (1 Chr 9:17-27). The one-digit divergence is the minimal scribal error type. The six clan names correspond to the six principal gatekeeper positions.</p>",
    "46": "<p>The temple servants (<em>nəṯînîm</em>) begin at v46 and extend through v56 — a much longer list than the laity or clergy sections. <em>Ziḥāʾ, Ḥăšūp̄āʾ, Ṭabbāʾôṯ</em>: non-Israelite names suggesting the Nethinim's foreign origin (Josh 9:27 Gibeonites; additional groups incorporated under David and Solomon). Their names — many identifiable as Canaanite, Egyptian, or otherwise foreign — witness to the incorporation of non-Israelite temple workers into the covenant community over centuries.</p>",
    "47": "<p><em>Qērôs, Sîʾāʾ, Pāḏôn</em>: more Nethinim names. <em>Qeros</em> may be related to an Edomite name root; <em>Padon</em> = 'ransom/redemption.' The presence of names meaning 'redemption' among temple servants is poignant — those who served in the sanctuary bore names reflecting the theological content of their service environment.</p>",
    "48": "<p><em>Ləḇānāʾ, Ḥăgāḇāʾ, Šalmay</em>: Nethinim names. <em>Lēḇānāh</em> = 'white/moon'; <em>Ḥăgāḇ</em> = 'locust' (same root as the locust of Joel 1:4). The diverse etymologies of these names — some theophoric, some nature-based, some of uncertain origin — reflect the cosmopolitan origins of the Nethinim population.</p>",
    "49": "<p><em>Ḥānān, Giddēl, Gaḥar</em>: Nethinim names. <em>Ḥānān</em> = 'gracious' (shortened theophoric form of Hananiah). <em>Giddel</em> = 'great/magnified.' The theophoric and honorific names among the Nethinim reflect their integration into the Hebrew naming culture over generations of service in the temple.</p>",
    "50": "<p><em>Rəʾāyāh, Rəṣîn, Nəqôḏāʾ</em>: Nethinim names. <em>Rəʾāyāh</em> = 'YHWH has seen'; <em>Rəṣîn</em> is the name of the Aramean king of Damascus in 2 Kgs 16:5 — a foreign name carried by a temple servant whose ancestors may have been war captives incorporated into temple service.</p>",
    "51": "<p><em>Gazzām, ʿUzzāʾ, Pāsēaḥ</em>: Nethinim names. <em>Gazzam</em> = 'devouring locust' (cf. Joel 1:4 gāzām); <em>Uzza</em> = 'strength.' The locust-name among temple servants may echo the agricultural devastation reversed by covenant faithfulness in Joel's restoration promise.</p>",
    "52": "<p><em>Bēsay, Məʿûnîm, Nəp̄išəsîm</em>: Nethinim names. <em>Meunim</em> refers to a people from Maan in Edom (cf. 1 Chr 4:41; 2 Chr 20:1 — the Meunites were a people from southeast of the Dead Sea). Their descendants serve in Jerusalem's temple — another witness to the inclusion of formerly hostile peoples into covenant service.</p>",
    "53": "<p><em>Baqbûq, Ḥăqûp̄āʾ, Ḥarḥûr</em>: Nethinim names of uncertain etymology. <em>Baqbuq</em> = 'bottle/flask' (onomatopoeia for the sound of liquid poured from a narrow-necked vessel). The mundane name-origins among the Nethinim contrast with the sacred function they serve — the ordinary become holy by assignment to YHWH's house.</p>",
    "54": "<p><em>Baṣlîṯ, Məḥîḏāʾ, Ḥaršāʾ</em>: Nethinim names. <em>Harsha</em> = 'magician/enchanter' — a foreign name possibly indicating an ancestor associated with occult practice before incorporation into covenant service. That such names appear among temple servants is a remarkable witness to the transforming power of covenant membership.</p>",
    "55": "<p><em>Barqôs, Sîsərāʾ, Tāmaḥ</em>: Nethinim names. <em>Sisera</em> is the name of the Canaanite general slain by Jael (Judg 4:2). That a family bearing Sisera's name appears among temple servants in Jerusalem is one of the most striking name-survivals in the OT: the former enemy's name is preserved among those who serve YHWH in his house.</p>",
    "56": "<p><em>Nəṣîaḥ, Ḥăṭîp̄āʾ</em>: the last Nethinim names. The extended Nethinim list (vv46-56) underscores the large and diverse population serving in the temple. Their inclusion in the official registry, alongside priests and Levites, affirms their status as legitimate members of the worshiping community despite (or through) their non-Israelite origins.</p>",
    "57": "<p>The descendants of Solomon's servants (<em>ʿaḇdê šəlōmōh</em>) follow the Nethinim. Three families: <em>Sōṭay, Sōp̄ereṯ, Pərîḏāʾ</em>. <em>Sophereth</em> = 'scribe' (fem. form of <em>sōpēr</em>); these temple servants bore a scribal-vocation name, possibly indicating an ancestor who served in Solomon's royal scribal bureau before being incorporated into temple service.</p>",
    "58": "<p><em>Yaʿălāʾ, Darqôn, Giddēl</em>: more of Solomon's servants. <em>Darkon</em> = possibly from a root meaning 'way/path.' The 'servants of Solomon' (<em>ʿaḇdê šəlōmōh</em>) are a distinct class from the Nethinim, though both serve in the temple — their ancestor category traces back to Solomon's labor force rather than to David's Nethinim institution.</p>",
    "59": "<p><em>Šəp̄aṭyāh, Ḥaṭṭîl, Pôḵereṯ-haṣṣəḇāyîm, ʾĀmôn</em>: the last of Solomon's servants. <em>Pokereth-hazzebaim</em> = 'gazelle-binder' — a trade name describing an ancestor who worked with gazelles, possibly in the royal hunting grounds. The name's preservation across the exile and return demonstrates the tenacity of occupational family identity in ancient Near Eastern genealogical practice.</p>",
    "60": "<p><strong>kol-hannəṯînîm ûḇənê ʿaḇdê šəlōmōh šəlōš mēʾôṯ tiš'îm ûšnāyim</strong> — 'All the temple servants and descendants of Solomon's servants: 392' (cf. Ezra 2:58: 392 — match). The combined total matches exactly, though the individual family counts vary between Ezra 2 and Neh 7. The exact total-match with individual divergences suggests the totals were calculated independently from the individual entries in each list, and the totals were preserved accurately while individual entries suffered scribal variation.</p>",
    "61": "<p><strong>wəʾēlleh hāʿōlîm mittəl-melaḥ</strong> — 'And these are those who came up from Tel-melah, Tel-harsha, Cherub, Addon, and Immer.' Five Babylonian place-names; <em>tēl</em> = mound/ruin (indicating Babylonian sites). <strong>wəlōʾ yāḵlû ləhaggîḏ bêṯ-ʾăḇôṯāhem wəzarʿām</strong> — 'they could not declare their father's house or their seed/ancestry.' The inability to establish genealogical credentials (<em>yāḥas</em>) created a legal problem for those claiming covenant membership. Without verifiable ancestry, covenant rights could not be established.</p>",
    "62": "<p>Delaiah, Tobiah, and Nekoda: 642 (cf. Ezra 2:60: 652 — diverge by 10). These individuals could not verify their Israelite descent. <em>Ṭôḇiyyāh</em> ('YHWH is good') — notably the same name as Nehemiah's persistent opponent (Neh 2:10; 4:3). Whether any connection is intended is uncertain; the name was common. The ten-person divergence in this entry is consistent with the general transmission pattern.</p>",
    "63": "<p><strong>ûmin-hakkōhănîm</strong> — 'Among the priests,' the problematic cases are more serious: those who claimed priestly descent but could not verify it were excluded from priestly functions. <em>Barzillay</em> married a daughter of the lay Barzillai (cf. 2 Sam 19:31-39) and 'was called by their name' — took a wife's family name, which legally complicated his priestly genealogy. The genealogical complexity of mixed-heritage claims mirrors the Ezra 10 intermarriage crisis.</p>",
    "64": "<p><strong>wayyəḇaqšū kəṯāḇām hammityyaḥăśîm wəlōʾ nimṣāʾ</strong> — 'They searched for their names in the genealogical register (<em>kəṯāḇ hayyiṯyaḥēś</em>) but were not found.' The written register (<em>kəṯāḇ</em> = writing/document) is the authoritative source; unregistered claims cannot stand. <strong>wayyəgōʾălû min-hakkəhunnāh</strong> — 'they were disqualified from the priesthood' (<em>gāʾal</em>, H1351 = to defile/pollute; in context, exclude as unclean). The same verb used for ritual pollution is applied to genealogical disqualification — unverifiable genealogy renders priestly service ritually invalid.</p>",
    "65": "<p><strong>ʿad ʿămōḏ hakkōhēn ləʾûrîm wəṯummîm</strong> — 'until a priest arose who could consult the Urim and Thummim.' This is one of the last mentions of the Urim and Thummim (H224 ʾûrîm = lights; H8550 tummîm = perfections/completions) in the Hebrew Bible. The Urim and Thummim were the oracular objects in the High Priest's breastpiece (Exod 28:30) used to obtain divine answers. By the Second Temple period, the rabbis believed the Urim and Thummim had ceased to function — the provision here is therefore an open-ended deferral: the question of these priests' eligibility is suspended until divine oracle resumes. In effect, an eschatological provision is embedded in a practical administrative decision.</p>",
    "66": "<p><strong>kol-haqqāhāl kəʾeḥāḏ ʾarbaʿ-rîbbôʾ ūšənayim ʾălāp̄îm šəlōš mēʾôṯ šiššîm</strong> — 'The whole assembly together: 42,360.' This total matches Ezra 2:64 exactly (42,360) despite the numerous divergences in individual entries. The matching grand total with divergent sub-totals is a known phenomenon in ancient record-keeping: the sum was maintained separately and more carefully than the enumerated parts. The number 42,360 is also approximately 10 times 4,236 — which may or may not be significant for the scribal tradition.</p>",
    "67": "<p>7,337 male and female servants plus 245 singers (cf. Ezra 2:65: 7,337 servants but 200 singers — diverge by 45 on singers). The servants (<em>ʿaḇādîm wəšip̄ḥôṯ</em>, male and female slaves) are not counted in the 42,360 total — they are a dependent population outside the covenant-member count. The 245 vs. 200 divergence in singers may reflect the addition of singers to the entertainment/ceremony roster after the initial return.</p>",
    "68": "<p>736 horses, 245 mules (cf. Ezra 2:66: 736 horses, 245 mules — match). The presence of horses and mules among the returnees indicates significant economic capacity — draft animals for agriculture and transport, war-horses for those who had served in Babylonian/Persian service. The matching numbers confirm stable transmission of the animals census.</p>",
    "69": "<p>435 camels, 6,720 donkeys (cf. Ezra 2:67: 435 camels, 6,720 donkeys — match). The donkey count (6,720) is the largest animal total — donkeys were the primary pack and riding animal of ancient Judah. All four animal totals match exactly between Ezra 2 and Nehemiah 7, confirming that the animal census was transmitted with greater accuracy than the human sub-totals.</p>",
    "70": "<p><strong>ûmiqqəṣāt rāʾšê hāʾāḇôṯ nāṯənû</strong> — 'some of the family heads gave.' The voluntary gifts for the work (<em>hammělāʾḵāh</em>) mirror the tabernacle-construction freewill offerings (Exod 36:3-7). The governor (<em>hattirşāṯāʾ</em>) — the Persian-derived title for the governor of Judah — gives 1,000 gold drachmas, 50 basins, and 530 priestly garments. The combination of gold, liturgical vessels, and vestments covers the full range of temple needs.</p>",
    "71": "<p>Family heads give 20,000 gold drachmas and 2,200 silver minas for the treasury. The voluntary character of the giving (<em>nāṯənû</em>, simple qal = 'gave,' not 'paid') matches the freewill principle of Exod 35:5 (<em>kol-nəḏîḇ libbô</em> = 'whoever is willing in heart'). The gifts fund the re-establishment of temple service without imperial compulsion.</p>",
    "72": "<p>The rest of the people give 20,000 gold drachmas, 2,000 silver minas, and 67 priestly garments. The three-tier giving structure (governor, family heads, people at large) models proportional generosity — each level gives according to capacity, all contributing to the same purpose. The <em>priestly garments</em> (<em>kuttōnōṯ kəhunnāh</em>) are practical necessities for the priestly service to resume.</p>",
    "73": "<p><strong>wayyēšəḇû hakkōhănîm wəhalwiyyîm wəhašşōʿărîm wəhamšōrərîm wəmin-hāʿām wəhannəṯînîm wəḵol-yiśrāʾēl bəʿārêhem</strong> — 'the priests, Levites, gatekeepers, singers, some of the people, the temple servants, and all Israel settled in their towns.' The comprehensive formula — naming each temple-service class — mirrors the language of settlement from Joshua (Josh 21:43-45). The transitional phrase connects the genealogical register to the Torah-reading assembly of ch. 8: <strong>ûḵaḇōʾ haḥōdeš haššəḇîʿî</strong> = 'and when the seventh month came.' The seventh month (Tishri) contains the Day of Atonement and the Feast of Tabernacles — the most sacred days of the covenant calendar.</p>"
  },
  "8": {
    "1": "<p><strong>wayyēʾāsəp̄û kol-hāʿām kəʾîš ʾeḥāḏ</strong> — 'all the people gathered as one man.' The phrase <em>kəʾîš ʾeḥāḏ</em> ('as one man') occurs at two national crises: here for covenant renewal, and Judg 20:1 for the assembly to address the Gibeah atrocity. The unity idiom marks a decisive national moment. <strong>ʾel-hārəḥôḇ ʾăšer lip̄nê šaʿar hammayim</strong> — 'in the square before the Water Gate.' The Water Gate (šaʿar hammayim) is on the eastern wall; the square before it was one of Jerusalem's largest open gathering spaces. The public, outdoor character of the assembly is significant — Torah reading is not a private or priestly event.</p>",
    "2": "<p><strong>wayyābêʾ ʿEzrāʾ hakkōhēn ʾeṯ-hattôrāh</strong> — 'Ezra the priest brought the Torah.' <em>Hattôrāh</em> with the definite article: 'the Torah' — the specific scroll, almost certainly the Pentateuch or a significant portion thereof. <strong>lip̄nê haqqāhāl</strong> — 'before the assembly' (<em>qāhāl</em>, H6951 = the assembled congregation; the covenantal term for Israel gathered). The date: first day of the seventh month = Rosh Hashanah, the New Year — a new beginning that inaugurates the Tishri holy-days cycle.</p>",
    "3": "<p><strong>wayyiqrāʾ-ḇô lip̄nê hārəḥôḇ ʾăšer lip̄nê šaʿar hammayim min-hāʾôr ʿaḏ maḥăṣît hayyôm</strong> — 'he read from it in the square before the Water Gate from the light until half-day (noon).' Six hours of uninterrupted public Torah reading. <em>Min-hāʾôr</em> = 'from the light' (dawn). The congregation's sustained attention for six hours without written copies reflects a culture of oral tradition and active listening. <strong>wəʾoznê kol-hāʿām ʾel-sēfer hattôrāh</strong> — 'all the people's ears toward the Book of the Torah' — attentive hearing is described as physical orientation of the ear.</p>",
    "4": "<p><strong>ʿal-migdal-ʿēṣ ʾăšer ʿāśû laddāḇār</strong> — 'on a wooden tower (<em>migdāl-ʿēṣ</em>, lit. 'tower of wood') that they built for the occasion.' The platform was purpose-built for this specific public reading — an elevated pulpit from which Ezra could be seen and heard by the large assembly. The 13 named men standing on his right and left provide witnesses to the authoritative reading. The reading platform (bimah in later synagogue practice) originates in this passage.</p>",
    "5": "<p><strong>wayyipptaḥ ʿEzrāʾ hassēfer lěʿênê kol-hāʿām</strong> — 'Ezra opened the book before the eyes of all the people.' The opening of the scroll (<em>pāṯaḥ</em> = to open) is a visible act witnessed by the whole assembly. <strong>kî-ḵol-hāʿām rāʾû ḵî-ʿāmōḏ</strong> — 'for all the people could see him when he stood' (lit. 'for he was standing above them'). The elevation of the reading creates a visual ceremonial: the congregation sees the scroll opened above them. <strong>wayyaʿămōḏ kol-hāʿām</strong> — 'all the people stood.' Rising for the reading of Torah — the origin of the synagogue practice of standing for the Torah reading — is first attested here.</p>",
    "6": "<p><strong>waybāreḵ ʿEzrāʾ ʾeṯ-YHWH hāʾĕlōhîm haggāḏôl</strong> — 'Ezra blessed the LORD the great God.' The doxology precedes the reading — praise frames the word. <strong>wayyaʿănû kol-hāʿām ʾāmēn ʾāmēn</strong> — 'all the people answered, Amen! Amen!' The double amen (<em>ʾāmēn ʾāmēn</em>) is emphatic — 'truly, truly.' <em>ʾĀmēn</em> (H543) derives from <em>ʾāman</em> (H539, to be faithful/firm/sure); the congregational amen is a vocal ratification of what has been said, affirming it as certain truth. The double amen form appears in the Psalms (Ps 41:13; 72:19; 89:52; 106:48) as a doxological conclusion. Jesus's <em>ʾāmēn ʾāmēn légo hymin</em> ('truly, truly I say to you') uses the same double form.</p>",
    "7": "<p>Thirteen Levites named as having 'made the people understand' (<em>mēḇînîm ʾeṯ-hāʿām</em> — hiphil participle of <em>bîn</em>, H995 = to understand/discern, here causative: 'causing to understand'). The Levitical teaching function in this verse is explicitly causative: their role is not to read but to <em>produce understanding</em> in the hearers. The list of 13 names mirrors the 13 on the reading platform (v4) — possibly the same individuals who read from the platform now teach in the assembly. Sherebiah and Hashabiah (Levites who returned with Ezra, Ezra 8:18-19) are named here.</p>",
    "8": "<p><strong>wayyiqrəʾû bassēfer bəṯôrat hāʾĕlōhîm məpōrāš wəśôm śeḵel wayyāḇînû bammiqrāʾ</strong> — 'They read from the Book of the Law of God, clearly (<em>məpōrāš</em>), giving the meaning (<em>śôm śeḵel</em>), and they gave insight into the reading.' This verse is the foundational text for biblical exposition. Three key terms: (1) <em>məpōrāš</em> (pual/hiphil participle of <em>pāraš</em>, H6567 = to make distinct, separate, articulate; hence 'clearly, distinctly, with explanation'); (2) <em>śôm śeḵel</em> (lit. 'placing/applying insight' — <em>śeḵel</em>, H7922 = understanding/prudence); (3) <em>wayyāḇînû bammiqrāʾ</em> ('they understood in/through the reading'). The triad describes an expositor's task: read the text → explain it clearly → apply understanding → produce comprehension. The Aramaic Targum tradition (<em>meturgemān</em> = interpreter) traces its roots to this verse and practice.</p>",
    "9": "<p><strong>kî-ḇāḵû kol-hāʿām kəšomʿām ʾeṯ-diḇrê hattôrāh</strong> — 'for all the people wept as they heard the words of the Torah.' The tears arise not from sorrow but from the weight of the word landing on their hearts after a generation of exile — hearing God's covenant terms with fresh ears. <strong>hayyôm qāḏôš hûʾ lăʾaḏōnāy ʾĕlōhêkem</strong> — 'This day is holy to the LORD your God.' Nehemiah, Ezra, and the Levites all make the same pronouncement: the holiness of the day forbids grief-expressions appropriate to mourning but inappropriate to a feast day.</p>",
    "10": "<p><strong>ləḵû ʾiḵlû maš manim ûšəṯû məṯāqîm ûšilḥû mānôṯ</strong> — 'Go and eat choice foods and drink sweet drinks and send portions.' The triple imperatives (<em>ʾiḵlû, šəṯû, šilḥû</em>) command celebratory eating, drinking, and sharing. The sharing of portions with those who have nothing reflects the covenant-feast pattern (Deut 16:11,14 'you shall rejoice… including the Levite, the sojourner, the fatherless'). <strong>kî-ḥeḏwaṯ-YHWH hî māʿuzzəkem</strong> — 'for the joy of the LORD is your strength.' <em>Ḥeḏwāh</em> (H2304 = joy, gladness) is a rare word (only here and in Ps 21:6; 1 Chr 16:27; Ezra 6:16). It differs from the more common <em>śimḥāh</em> (H8057) and <em>gîl</em> (H1524). <em>Māʿôz</em> (H4581) = stronghold, place of refuge, strength. The construction is: the joy that comes from (being in the presence of) the LORD is itself a refuge/stronghold. Joy is not merely emotional but protective — a theological category of covenant security.</p>",
    "11": "<p><strong>haššəṭû kol-hāʿām</strong> — 'Quiet all the people!' Hiphil imperative of <em>šāqaṭ</em> (H8252 = to be quiet, still, at rest). The Levites call for reverent silence — the appropriate response to holiness is not emotional weeping (which expresses fear/guilt) but joyful calm. The tension between deep emotional response (tears at v9) and commanded joy (vv10-11) reflects the two-sided reality of encountering God's word: conviction of sin and delight in grace are both appropriate responses, calibrated to the liturgical moment.</p>",
    "12": "<p><strong>wayyāḇînû haddəḇārîm ʾăšer hôḏîʿû lāhem</strong> — 'they understood the words that had been made known to them.' The verb <em>bîn</em> (hiphil in v7 = 'caused to understand'; now qal in v12 = 'they understood') marks the completion of the teaching arc: the Levites' causative action (v7) produced the desired result (v12). Understanding is the goal; the feast is the appropriate response to understanding received. The joy (<em>śimḥāh gəḏôlāh</em>, great joy) arises specifically from understanding, not merely from hearing.</p>",
    "13": "<p><strong>ûḇayyôm haššênî nēʾăsəp̄û rāʾšê hāʾāḇôṯ</strong> — 'On the second day, the family heads gathered.' The voluntary return for deeper study models the hunger for God's word that authentic encounter produces: one encounter generates more hunger, not satiation. <strong>ləhaśkîl ʾel-diḇrê hattôrāh</strong> — 'to gain insight into the words of the Torah.' <em>Haśkîl</em> (hiphil of <em>śākal</em>, H7919 = to understand/have insight/act wisely) is the intellectual and practical wisdom term: not just to understand Torah intellectually but to act wisely in accordance with it.</p>",
    "14": "<p><strong>wayyimṣəʾû kātûḇ battôrāh</strong> — 'they found it written in the Torah.' The phrase marks the hermeneutical moment: reading to discover what YHWH has commanded. <strong>ʾăšer ṣiwwāh YHWH bəyaḏ-Mōšeh</strong> — 'which the LORD commanded by the hand of Moses' — the Mosaic authority behind the specific commandment (Lev 23:40-43) is explicitly invoked. The discovery pattern — reading, finding written, implementing — is a model of Torah-driven reform (cf. 2 Kgs 22:13 Josiah's discovery of the Torah scroll; 2 Chr 34:14-21).</p>",
    "15": "<p>The proclamation to gather branches of olive, myrtle, palm, and leafy trees for booths (<em>sukkôṯ</em>) is drawn directly from Lev 23:40. The species named — <em>ʿēṣ-šemeš</em> (lit. 'oil-tree,' = oleander or wild olive), <em>hadaś</em> (myrtle), <em>tāmār</em> (palm), and <em>ʿēṣ āḇôṯ</em> (leafy/boughy trees) — correspond to the Levitical prescription. The application of a 1,000-year-old text to a specific community action models the normativity of written Scripture: 'it is written' → 'therefore we do.'</p>",
    "16": "<p>The booths are built everywhere — rooftops, courts, temple courts, the square of the Water Gate, the square of the Ephraim Gate. The ubiquity of the booths transforms the entire city into a visible embodiment of the Sukkoth command. The public, city-wide visibility of the celebration is itself a form of covenant witness: the physical transformation of Jerusalem for seven days announces to all observers that the returned community lives under God's covenant obligations.</p>",
    "17": "<p><strong>miymê yēšûaʿ bin-nûn ʿaḏ-hayyôm hahûʾ lōʾ-ʿāśû ḵēn bənê yiśrāʾēl</strong> — 'From the days of Joshua son of Nun until that day the sons of Israel had not done such.' The superlative 'from the days of Joshua' places this Sukkoth celebration as the greatest since the conquest — eclipsing even the Solomonic temple celebration. Note: 2 Chr 35:18 makes a similar claim for Josiah's Passover ('from the days of Samuel'), but each claim concerns a different feast (Sukkoth here, Passover there) and a different comparison baseline. <em>Śimḥāh gəḏôlāh məʾōḏ</em> — 'very great joy' — the superlative <em>məʾōḏ</em> intensifies the great joy of v12 to its maximum degree.</p>",
    "18": "<p><strong>wayyiqrāʾ bəsēfer Tôrat-hāʾĕlōhîm yôm bəyôm</strong> — 'And he read from the Book of the Law of God day by day.' The daily Torah reading throughout the seven-day feast (plus the eighth-day sacred assembly, <em>ʿăṣāreṯ</em>, H6116 = concluding assembly/solemn convocation, Lev 23:36) is the liturgical culmination of the water-gate assembly. The word <em>ʿăṣāreṯ</em> (from <em>ʿāṣar</em> = to restrain/hold back) designates the final convening of a feast period — the community is 'gathered in' one last time before dispersal. Daily consecutive Scripture reading as a congregational practice originates in this Nehemiah passage.</p>"
  }
}

def main():
    c = load_comm('mkt-original', 'nehemiah')
    merge_comm(c, NEH)
    save_comm('mkt-original', 'nehemiah', c)
    count = sum(len(v) for v in NEH.values())
    print(f'nehemiah mkt-original: wrote {count} verses for ch 7-8')

if __name__ == '__main__':
    main()
